css:
:root{
--bg:#04060b;--s1:#0b0e18;--s2:#111628;--s3:#181e35;
--brd:#1e2545;--brd2:#2d3560;
--tx:#ccd0e8;--tx2:#7d83a8;--tx3:#555b80;
--w:#f0f2ff;
--react:#61dafb;--react-bg:rgba(97,218,251,.06);--react-brd:rgba(97,218,251,.2);
--next-w:#ffffff;--next-bg:rgba(255,255,255,.04);
--green:#22d3a7;--red:#f06070;--yellow:#f5b731;--purple:#9b7afa;--blue:#4da6ff;--pink:#f472b6;--orange:#fb923c;
--code-bg:#070a12;
--r:10px;
}
*{margin:0;padding:0;box-sizing:border-box}
html{scroll-behavior:smooth}
body{font-family:'Plus Jakarta Sans',sans-serif;background:var(--bg);color:var(--tx);line-height:1.72;font-size:14.5px;-webkit-font-smoothing:antialiased}
::-webkit-scrollbar{width:5px}::-webkit-scrollbar-track{background:var(--bg)}::-webkit-scrollbar-thumb{background:var(--react);border-radius:9px}

.hero{padding:3.5rem 1.5rem 2rem;text-align:center;position:relative;overflow:hidden}
.hero::before{content:'';position:absolute;inset:0;background:radial-gradient(ellipse 70% 50% at 50% 0%,rgba(97,218,251,.09),transparent 65%);pointer-events:none}
.hero h1{font-family:'Fraunces',serif;font-size:clamp(2rem,5.5vw,3.8rem);font-weight:900;color:var(--w);letter-spacing:-.03em;line-height:1.12;position:relative}
.hero h1 .rc{color:var(--react)}
.hero .sub{color:var(--tx2);margin-top:.6rem;font-size:.95rem;max-width:560px;margin-inline:auto}
.hero .tags{display:flex;gap:.6rem;justify-content:center;margin-top:1.2rem;flex-wrap:wrap}
.hero .tag{font-size:.68rem;font-weight:700;padding:.3rem .75rem;border-radius:20px;letter-spacing:.06em;text-transform:uppercase}
.tag-r{background:var(--react-bg);color:var(--react);border:1px solid var(--react-brd)}
.tag-n{background:var(--next-bg);color:var(--next-w);border:1px solid rgba(255,255,255,.15)}
.tag-s{background:rgba(155,122,250,.08);color:var(--purple);border:1px solid rgba(155,122,250,.2)}

.nav{position:sticky;top:0;z-index:999;background:rgba(4,6,11,.88);backdrop-filter:blur(22px);border-bottom:1px solid var(--brd);overflow-x:auto;white-space:nowrap;-webkit-overflow-scrolling:touch}
.nav::-webkit-scrollbar{height:0}
.nav-inner{display:flex;max-width:1300px;margin:0 auto;padding:0 .5rem}
.nav-btn{background:0;border:0;color:var(--tx3);font-family:'Plus Jakarta Sans',sans-serif;font-size:.76rem;font-weight:500;padding:.8rem 1rem;cursor:pointer;border-bottom:2px solid transparent;transition:.2s;white-space:nowrap}
.nav-btn:hover{color:var(--tx)}
.nav-btn.active{color:var(--react);border-bottom-color:var(--react)}

.main{max-width:880px;margin:0 auto;padding:1.5rem 1.25rem 6rem}
.section{display:none;animation:fadeUp .3s ease}.section.active{display:block}
@keyframes fadeUp{from{opacity:0;transform:translateY(10px)}to{opacity:1;transform:translateY(0)}}
.section-intro{font-size:.95rem;color:var(--tx2);margin-bottom:1.75rem;padding-bottom:1.25rem;border-bottom:1px solid var(--brd)}

.card{background:var(--s1);border:1px solid var(--brd);border-radius:var(--r);padding:1.65rem;margin-bottom:1.15rem;transition:border-color .3s}
.card:hover{border-color:var(--brd2)}
.card h2{font-family:'Fraunces',serif;font-size:1.35rem;font-weight:700;color:var(--w);margin-bottom:.7rem}
.card h3{font-size:1rem;font-weight:700;color:var(--green);margin:1.3rem 0 .55rem}
.card h4{font-size:.88rem;font-weight:600;color:var(--purple);margin:1.1rem 0 .4rem}

pre{background:var(--code-bg);border:1px solid var(--brd);border-radius:8px;padding:1.1rem;overflow-x:auto;margin:.55rem 0;font-size:.78rem;line-height:1.65;tab-size:2}
code{font-family:'JetBrains Mono',monospace;font-size:.78rem}
p code,li code{background:var(--s2);padding:.12em .4em;border-radius:4px;color:var(--pink);font-size:.78em}
.kw{color:#c792ea}.st{color:#c3e88d}.cm{color:#546e7a}.fn{color:#82aaff}.dc{color:#ffcb6b}.nu{color:#f78c6c}.ty{color:#f07178}

.qa{background:var(--s1);border:1px solid var(--brd);border-radius:var(--r);margin-bottom:.55rem;overflow:hidden}
.qa-h{padding:.9rem 1.1rem;cursor:pointer;display:flex;align-items:flex-start;gap:.7rem;user-select:none;transition:background .2s}
.qa-h:hover{background:var(--s2)}
.lvl{font-family:'JetBrains Mono',monospace;font-size:.58rem;font-weight:600;padding:.15rem .5rem;border-radius:20px;text-transform:uppercase;letter-spacing:.04em;flex-shrink:0;margin-top:.18rem}
.lvl.b{background:rgba(34,211,167,.1);color:var(--green)}
.lvl.i{background:rgba(245,183,49,.1);color:var(--yellow)}
.lvl.a{background:rgba(240,96,112,.1);color:var(--red)}
.qq{font-weight:600;font-size:.87rem;color:var(--w);flex:1}
.tog{color:var(--tx3);font-size:1.1rem;flex-shrink:0;transition:transform .3s;margin-top:.05rem}
.qa.open .tog{transform:rotate(45deg)}
.qa-a{max-height:0;overflow:hidden;transition:max-height .5s ease}
.qa.open .qa-a{max-height:12000px}
.qa-ai{padding:0 1.1rem 1.1rem}
.qa-ai p{margin-bottom:.4rem}

.analogy{background:rgba(155,122,250,.06);border-left:3px solid var(--purple);border-radius:0 8px 8px 0;padding:.85rem 1rem;margin:.6rem 0;font-size:.85rem}
.analogy::before{content:'💡 Think of it this way';display:block;font-weight:700;font-size:.7rem;color:var(--purple);text-transform:uppercase;letter-spacing:.05em;margin-bottom:.3rem}
.tip{background:rgba(34,211,167,.06);border-left:3px solid var(--green);border-radius:0 8px 8px 0;padding:.85rem 1rem;margin:.6rem 0;font-size:.85rem}
.tip::before{content:'🔥 Pro Tip';display:block;font-weight:700;font-size:.7rem;color:var(--green);text-transform:uppercase;letter-spacing:.05em;margin-bottom:.3rem}
.warn{background:rgba(245,183,49,.06);border-left:3px solid var(--yellow);border-radius:0 8px 8px 0;padding:.85rem 1rem;margin:.6rem 0;font-size:.85rem}
.warn::before{content:'⚠️ Common Mistake';display:block;font-weight:700;font-size:.7rem;color:var(--yellow);text-transform:uppercase;letter-spacing:.05em;margin-bottom:.3rem}
.deep{background:rgba(77,166,255,.06);border-left:3px solid var(--blue);border-radius:0 8px 8px 0;padding:.85rem 1rem;margin:.6rem 0;font-size:.85rem}
.deep::before{content:'🔬 Under the Hood';display:block;font-weight:700;font-size:.7rem;color:var(--blue);text-transform:uppercase;letter-spacing:.05em;margin-bottom:.3rem}

.fbar{display:flex;gap:.35rem;margin-bottom:1rem;flex-wrap:wrap}
.fbtn{background:var(--s1);border:1px solid var(--brd);color:var(--tx3);font-family:'Plus Jakarta Sans',sans-serif;font-size:.75rem;font-weight:500;padding:.4rem .85rem;border-radius:20px;cursor:pointer;transition:.2s}
.fbtn:hover{border-color:var(--tx3)}
.fbtn.active{background:var(--react);border-color:var(--react);color:#000}
.counter{font-size:.78rem;color:var(--tx3);margin-bottom:.8rem}.counter b{color:var(--react)}

ul,ol{padding-left:1.4rem;margin:.4rem 0}li{margin-bottom:.3rem}p{margin-bottom:.5rem}strong{color:var(--w)}
.grid2{display:grid;grid-template-columns:1fr 1fr;gap:.8rem;margin:.6rem 0}
@media(max-width:640px){.grid2{grid-template-columns:1fr}.card{padding:1.15rem}pre{padding:.85rem;font-size:.72rem}.qa-h{padding:.75rem .9rem}}

scripts:
document.querySelectorAll('.nav-btn').forEach(b=>{
  b.addEventListener('click',()=>{
    document.querySelectorAll('.nav-btn').forEach(x=>x.classList.remove('active'));
    document.querySelectorAll('.section').forEach(x=>x.classList.remove('active'));
    b.classList.add('active');
    const target=document.getElementById(b.dataset.s);
    if(target)target.classList.add('active');
    window.scrollTo({top:document.querySelector('.nav').offsetTop,behavior:'smooth'});
  });
});
document.querySelectorAll('.qa-h').forEach(h=>{
  h.addEventListener('click',()=>h.parentElement.classList.toggle('open'));
});
function updateCounts(section){
  const vis=section.querySelectorAll('.qa:not([style*="display: none"])').length;
  const counter=section.querySelector('.vis-count');
  if(counter)counter.textContent=vis;
}
document.querySelectorAll('.fbtn').forEach(btn=>{
  btn.addEventListener('click',()=>{
    const section=btn.closest('.section');
    section.querySelectorAll('.fbtn').forEach(b=>b.classList.remove('active'));
    btn.classList.add('active');
    const f=btn.dataset.f;
    section.querySelectorAll('.qa').forEach(qa=>{
      qa.style.display=(f==='all'||qa.dataset.l===f)?'':'none';
    });
    updateCounts(section);
  });
});
document.querySelectorAll('.section').forEach(s=>updateCounts(s));
